(async function() {
  console.log("InvestSmart CSE Update: assembling payload...");
  window._b64 = '';
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "";
  window._b64 += "dXRoZW50aWNhdGlvbioKIiIiKQo=";
  console.log("Payload assembled:", window._b64.length, "chars");
  
  // Fetch current SHA from GitHub
  const OWNER = "vinupahelitha";
  const REPO  = "investsmart";
  const PATH  = "app.py";
  const TOKEN = prompt("Paste your GitHub PAT (classic, repo scope):");
  if (!TOKEN) { console.error("No token provided"); return; }
  
  const headers = {
    "Authorization": "token " + TOKEN,
    "Accept": "application/vnd.github.v3+json",
    "Content-Type": "application/json"
  };
  
  console.log("Fetching current file SHA...");
  const getResp = await fetch(
    `https://api.github.com/repos/${OWNER}/${REPO}/contents/${PATH}`,
    { headers }
  );
  if (!getResp.ok) {
    console.error("GET failed:", getResp.status, await getResp.text());
    return;
  }
  const fileData = await getResp.json();
  const sha = fileData.sha;
  console.log("Current SHA:", sha, "  size:", fileData.size);
  
  // Push updated file
  console.log("Pushing updated app.py...");
  const putResp = await fetch(
    `https://api.github.com/repos/${OWNER}/${REPO}/contents/${PATH}`,
    {
      method: "PUT",
      headers,
      body: JSON.stringify({
        message: "feat: Add full CSE Market page with live/15-min data, price board, stock detail, sector charts, Supabase history recording",
        content: window._b64,
        sha: sha
      })
    }
  );
  const result = await putResp.json();
  if (putResp.ok) {
    console.log("SUCCESS! Commit:", result.commit?.sha?.substring(0,8));
    alert("SUCCESS! CSE integration deployed. Commit: " + result.commit?.sha?.substring(0,8));
  } else {
    console.error("PUSH FAILED:", putResp.status, JSON.stringify(result));
    alert("PUSH FAILED: " + JSON.stringify(result));
  }
  window._b64 = '';
})();